import{_ as s,o as n,c as p,a4 as e}from"./chunks/framework.BDOgl-CJ.js";const x=JSON.parse('{"title":"Softmax 归一化、欧拉数 e 与求导","description":"","frontmatter":{},"headers":[],"relativePath":"ai-learning-notes/softmax-e-derivatives.md","filePath":"ai-learning-notes/softmax-e-derivatives.md","lastUpdated":1779693900000}'),t={name:"ai-learning-notes/softmax-e-derivatives.md"};function l(i,a,o,d,c,h){return n(),p("div",null,[...a[0]||(a[0]=[e(`<h1 id="softmax-归一化、欧拉数-e-与求导" tabindex="-1">Softmax 归一化、欧拉数 e 与求导 <a class="header-anchor" href="#softmax-归一化、欧拉数-e-与求导" aria-label="Permalink to &quot;Softmax 归一化、欧拉数 e 与求导&quot;">​</a></h1><blockquote><p>记录于 2026-05-25，手算 Self-Attention 时的推导<br> 从一道练习题顺藤摸瓜，挖到了微积分的根基</p></blockquote><hr><h2 id="softmax-公式" tabindex="-1">Softmax 公式 <a class="header-anchor" href="#softmax-公式" aria-label="Permalink to &quot;Softmax 公式&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>softmax(x_i) = e^x_i / Σ e^x_j</span></span></code></pre></div><p>三步走：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入：[1, 0, 1]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>① 每个数取 e 的幂：    [e^1, e^0, e^1] = [2.718, 1, 2.718]</span></span>
<span class="line"><span>② 求总和：             2.718 + 1 + 2.718 = 6.436</span></span>
<span class="line"><span>③ 每个除以总和：        [2.718/6.436, 1/6.436, 2.718/6.436]</span></span>
<span class="line"><span>                      = [0.422, 0.155, 0.422]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>验证：0.422 + 0.155 + 0.422 = 1 ✓</span></span></code></pre></div><p>核心：<strong>把任意数字变成概率分布</strong>（全部 ≥0，加起来 = 1）。</p><h3 id="用大白话说" tabindex="-1">用大白话说 <a class="header-anchor" href="#用大白话说" aria-label="Permalink to &quot;用大白话说&quot;">​</a></h3><p>三步，像分蛋糕：</p><p><strong>① 把每个人变&quot;正数&quot;</strong>（取 e 的幂）</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1 → 2.7</span></span>
<span class="line"><span>0 → 1</span></span>
<span class="line"><span>-3 → 0.05</span></span></code></pre></div><p>保证没有人是负数，都能分到蛋糕。</p><p><strong>② 全部加起来</strong> — 看看蛋糕总共多大</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2.7 + 1 + 2.7 = 6.4</span></span></code></pre></div><p><strong>③ 每人除以总和</strong> — 算出各自的比例</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2.7 ÷ 6.4 = 0.42</span></span>
<span class="line"><span>1   ÷ 6.4 = 0.16</span></span>
<span class="line"><span>2.7 ÷ 6.4 = 0.42</span></span></code></pre></div><p>结果：三份加起来 = 1。原来只看到 [1, 0, 1]，归一化后变成 [42%, 16%, 42%]——这个词用 42% 注意力，那个词只用 16%。</p><p>不是按年龄分，是按&quot;谁更饿&quot;（原始分数更大）分。越饿分到越多，但盘子永远是完整的一个。</p><hr><h2 id="为什么用-e-不用-10-或-2" tabindex="-1">为什么用 e，不用 10 或 2？ <a class="header-anchor" href="#为什么用-e-不用-10-或-2" aria-label="Permalink to &quot;为什么用 e，不用 10 或 2？&quot;">​</a></h2><p>换个底数也能归一化：</p><table tabindex="0"><thead><tr><th>底数</th><th>① 取幂</th><th>② /总和</th><th>结果</th></tr></thead><tbody><tr><td>e</td><td>e^1=2.72, e^0=1, e^1=2.72</td><td>/6.44</td><td>0.42, 0.16, 0.42</td></tr><tr><td>10</td><td>10^1=10, 10^0=1, 10^1=10</td><td>/21</td><td>0.48, 0.05, 0.48</td></tr><tr><td>2</td><td>2^1=2, 2^0=1, 2^1=2</td><td>/5</td><td>0.40, 0.20, 0.40</td></tr></tbody></table><p><strong>规律</strong>：底数越大，注意力越集中（大的更大，小的更小）。都能归一化。</p><p><strong>那为什么选 e？</strong></p><p>因为训练时要反向传播，要对 softmax <strong>求导</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(e^x)&#39;  = e^x           ← 导数 = 自己，干净</span></span>
<span class="line"><span>(10^x)&#39; = 10^x·ln(10)   ← 多一个常数 2.3</span></span>
<span class="line"><span>(2^x)&#39;  = 2^x·ln(2)    ← 多一个常数 0.69</span></span></code></pre></div><p>e 是<strong>唯一让导数等于自己的底数</strong>。论文不是偏爱 e，而是数学上只有它能做到。</p><hr><h2 id="求导是什么" tabindex="-1">求导是什么 <a class="header-anchor" href="#求导是什么" aria-label="Permalink to &quot;求导是什么&quot;">​</a></h2><p><strong>求导 = 问某一瞬间的变化速度。</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>y = x^2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>x=1 → y=1</span></span>
<span class="line"><span>x=2 → y=4  变化+3</span></span>
<span class="line"><span>x=3 → y=9  变化+5</span></span>
<span class="line"><span>x=4 → y=16 变化+7</span></span></code></pre></div><p>问：x=3 这一刻，y 的变化速度是多少？</p><p>用极限定义：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>f&#39;(x) = lim (f(x+Δx) - f(x)) / Δx</span></span>
<span class="line"><span>        Δx→0</span></span></code></pre></div><p>推导 y=x^2：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>((x+Δx)^2 - x^2) / Δx</span></span>
<span class="line"><span>= (x^2 + 2x·Δx + (Δx)^2 - x^2) / Δx   ← 展开平方</span></span>
<span class="line"><span>= (2x·Δx + (Δx)^2) / Δx                ← x^2 抵消</span></span>
<span class="line"><span>= 2x + Δx                              ← 约掉 Δx</span></span>
<span class="line"><span>→ 2x                                   ← Δx→0</span></span></code></pre></div><p><strong>y&#39; = 2x</strong>。x=3 时，瞬时速度 = 6。</p><hr><h2 id="欧拉数-e-从哪里来" tabindex="-1">欧拉数 e 从哪里来 <a class="header-anchor" href="#欧拉数-e-从哪里来" aria-label="Permalink to &quot;欧拉数 e 从哪里来&quot;">​</a></h2><p>e 不是拍脑袋定的，是算出来的：</p><blockquote><p>存 1 块钱，年利率 100%。如果无限次复利：</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>一年结一次：  (1 + 1)^1     = 2</span></span>
<span class="line"><span>半年结一次：  (1 + 0.5)^2   = 2.25</span></span>
<span class="line"><span>每月结一次：  (1+1/12)^12   = 2.613</span></span>
<span class="line"><span>每天结一次：  (1+1/365)^365 = 2.7146</span></span>
<span class="line"><span>⋮</span></span>
<span class="line"><span>无限趋近：    lim (1+1/n)^n  = e ≈ 2.71828</span></span>
<span class="line"><span>             n→∞</span></span></code></pre></div><p><strong>e 的意义：连续复利的极限。</strong> 任何「每一刻都在按当前值的比例增长」的现象，轨迹都是 e^x。</p><table tabindex="0"><thead><tr><th>现象</th><th>规律</th></tr></thead><tbody><tr><td>细菌繁殖</td><td>每秒按当前数量增长 → e^x</td></tr><tr><td>放射性衰变</td><td>每秒按当前数量衰减 → e^(-x)</td></tr><tr><td>钱生钱（连续复利）</td><td>理论上限 → e</td></tr></tbody></table><hr><h2 id="为什么-e-x-的导数是它自己" tabindex="-1">为什么 e^x 的导数是它自己 <a class="header-anchor" href="#为什么-e-x-的导数是它自己" aria-label="Permalink to &quot;为什么 e^x 的导数是它自己&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(e^x)&#39; = e^x</span></span></code></pre></div><p>因为 e 的定义就保证了这点：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(任意底数 a^x)&#39; = a^x · ln(a)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要让导数是自己，需要 ln(a) = 1</span></span>
<span class="line"><span>ln 等于 1 的那个数，就是 e</span></span></code></pre></div><p>类比：π 是「周长 ÷ 直径」= 3.14，e 是「ln=1 的那个数」≈ 2.718。都不是谁定的，是算出来的。</p><hr><h2 id="这些怎么串起来" tabindex="-1">这些怎么串起来 <a class="header-anchor" href="#这些怎么串起来" aria-label="Permalink to &quot;这些怎么串起来&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>手算 Attention 的 softmax 步骤</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>&quot;为什么是 e^x 不是 10^x？&quot;</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>因为训练时要反向传播（求导）</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>&quot;什么是求导？&quot;</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>极限定义：(f(x+Δx)-f(x))/Δx，Δx→0</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>&quot;为什么 e^x 求导 = 自己？&quot;</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>因为 e 的定义就是 ln(e)=1，令 (a^x)&#39;=a^x 的唯一解</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>&quot;e 从哪来？&quot;</span></span>
<span class="line"><span>  ↓</span></span>
<span class="line"><span>lim (1+1/n)^n，连续复利的极限</span></span></code></pre></div><p>一道 Attention 练习题，把微积分的根基全翻出来了。</p>`,55)])])}const g=s(t,[["render",l]]);export{x as __pageData,g as default};
